Here's a complete implementation:

## XAML

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             xmlns:models="clr-namespace:MyApp.Models"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}" FontSize="12"
                                   TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <Label Text="No items found."
                       HorizontalTextAlignment="Center"
                       VerticalOptions="Center" />
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

## ViewModel

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    public ItemsViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync(
            $"{nameof(DetailPage)}?id={CurrentItem.Id}");

        // Clear selection so user can re-select the same item
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false; // Must set false to hide spinner
        }
    }
}
```

## Key binding points

| XAML Property | ViewModel Property | Notes |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Set to `false` when refresh completes |
| `Command` (RefreshView) | `RefreshCommand` | Generated by `[RelayCommand]` on `RefreshAsync` |
| `SelectedItem` | `Item? CurrentItem` | Two-way so you can clear it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires when selection changes |
| `ItemsSource` | `ObservableCollection<Item>` | Use ObservableCollection, never List |

**Important details:**
- Wrap `CollectionView` in `RefreshView` for pull-to-refresh — CollectionView has no built-in refresh.
- Always set `IsRefreshing = false` in a `finally` block to dismiss the spinner.
- Clear `CurrentItem` after navigation so the same item can be tapped again.
- Use `x:DataType` on both the page and `DataTemplate` for compiled bindings.
